function DIJKSTRA(graph, source):
    dist[source] = 0
    priority_queue.add(source)
    while queue not empty:
        u = extract_min()
        for each neighbor v of u:
            if dist[v] > dist[u] + weight(u,v):
                dist[v] = dist[u] + weight(u,v)
                queue.add(v)
